// ─── Helpers ─────────────────────────────────────────────────────────────
function getInitials(name: string): string {
  if (!name || /^\d/.test(name)) return '?';
  const parts = name.trim().split(/\s+/);
  if (parts.length >= 2) return (parts[0][0] + parts[1][0]).toUpperCase();
  return name[0].toUpperCase();
}

function getAvatarColor(name: string): string {
  const colors = [
    'from-orange-400 to-orange-500',
    'from-blue-400 to-blue-500',
    'from-emerald-400 to-emerald-500',
    'from-purple-400 to-purple-500',
    'from-pink-400 to-pink-500',
    'from-cyan-400 to-cyan-500',
    'from-amber-400 to-amber-500',
    'from-indigo-400 to-indigo-500',
    'from-rose-400 to-rose-500',
    'from-teal-400 to-teal-500',
  ];
  let hash = 0;
  for (let i = 0; i < (name || '').length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
  return colors[Math.abs(hash) % colors.length];
}

function formatTime(dateStr: string, lang: string): string {
  const d = new Date(dateStr.endsWith?.('Z') ? dateStr : dateStr + 'Z');
  const now = new Date();
  const diffMs = now.getTime() - d.getTime();
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

  if (diffDays === 0) {
    return d.toLocaleTimeString(lang === 'ru' ? 'ru-RU' : 'uz-UZ', { hour: '2-digit', minute: '2-digit' });
  }
  if (diffDays === 1) return lang === 'ru' ? 'Вчера' : 'Kecha';
  if (diffDays < 7) {
    return d.toLocaleDateString(lang === 'ru' ? 'ru-RU' : 'uz-UZ', { weekday: 'short' });
  }
  return d.toLocaleDateString(lang === 'ru' ? 'ru-RU' : 'uz-UZ', { day: 'numeric', month: 'short' });
}

function formatMessageTime(dateStr: string, lang: string): string {
  const d = new Date(dateStr.endsWith?.('Z') ? dateStr : dateStr + 'Z');
  return d.toLocaleTimeString(lang === 'ru' ? 'ru-RU' : 'uz-UZ', { hour: '2-digit', minute: '2-digit' });
}

function formatDateSeparator(dateStr: string, lang: string): string {
  const d = new Date(dateStr.endsWith?.('Z') ? dateStr : dateStr + 'Z');
  const now = new Date();
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const msgDate = new Date(d.getFullYear(), d.getMonth(), d.getDate());
  const diffDays = Math.floor((today.getTime() - msgDate.getTime()) / (1000 * 60 * 60 * 24));

  if (diffDays === 0) return lang === 'ru' ? 'Сегодня' : 'Bugun';
  if (diffDays === 1) return lang === 'ru' ? 'Вчера' : 'Kecha';
  return d.toLocaleDateString(lang === 'ru' ? 'ru-RU' : 'uz-UZ', { day: 'numeric', month: 'long', year: 'numeric' });
}

/** Check if a last_message value is a real message text (not a number or empty) */
function getLastMessagePreview(channel: ChatChannel, lang: string): string {
  // Only show last_message if there's actually a last_message_at timestamp
  // This prevents showing stale data or numbers like "0" from message_count
  if (channel.last_message_at && channel.last_message && typeof channel.last_message === 'string' && channel.last_message.trim().length > 0) {
    return channel.last_message;
  }
  return lang === 'ru' ? 'Нет сообщений' : 'Xabar yo\'q';
}

// ─── Filter Tabs ─────────────────────────────────────────────────────────
type FilterTab = 'all' | 'unread';

// ─── Admin Channel Sidebar ──────────────────────────────────────────────
function AdminChannelList({
  channels,
  onSelectChannel,
  selectedChannelId,
  isLoading
}: {
  channels: ChatChannel[];
  onSelectChannel: (channelId: string) => void;
  selectedChannelId: string | null;
  isLoading: boolean;
}) {
  const { language } = useLanguageStore();
  const [searchQuery, setSearchQuery] = useState('');
  const [activeFilter, setActiveFilter] = useState<FilterTab>('all');
  const [showBranchFilter, setShowBranchFilter] = useState(false);
  const [selectedBranch, setSelectedBranch] = useState<string | null>(null);

  // Only count private_support channels
  const supportChannels = channels.filter(ch => ch.type === 'private_support');
  const totalUnread = supportChannels.reduce((sum, ch) => sum + (ch.unread_count || 0), 0);

  const sortChannels = (a: ChatChannel, b: ChatChannel) => {
    const aUnread = a.unread_count || 0;
    const bUnread = b.unread_count || 0;
    if (bUnread !== aUnread) return bUnread - aUnread;
    const aTime = a.last_message_at ? new Date(a.last_message_at).getTime() : 0;
    const bTime = b.last_message_at ? new Date(b.last_message_at).getTime() : 0;
    return bTime - aTime;
  };

  const filteredChannels = supportChannels.filter(ch => {
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      const matchesSearch = ch.name?.toLowerCase().includes(q) ||
        ch.description?.toLowerCase().includes(q) ||
        ch.last_message?.toLowerCase().includes(q) ||
        ch.resident_apartment?.toLowerCase().includes(q) ||
        ch.resident_building_name?.toLowerCase().includes(q);
      if (!matchesSearch) return false;
    }
    if (activeFilter === 'unread' && (!ch.unread_count || ch.unread_count === 0)) return false;
    if (selectedBranch && ch.resident_branch_name !== selectedBranch) return false;
    return true;
  }).sort(sortChannels);

  const branchNames = [...new Set(
    supportChannels
      .map(ch => ch.resident_branch_name)
      .filter((name): name is string => !!name)
  )].sort();

  const unreadCount = supportChannels.filter(ch => ch.unread_count && ch.unread_count > 0).length;

  return (
    <div className="h-full flex flex-col bg-white">
      {/* Header */}
      <div className="px-5 pt-5 pb-3">
        <div className="flex items-center justify-between mb-1">
          <h2 className="text-xl font-bold text-gray-900" style={{ fontFamily: "'Onest', sans-serif" }}>
            {language === 'ru' ? 'Сообщения' : 'Xabarlar'}
          </h2>
          {totalUnread > 0 && (
            <span className="px-2.5 py-1 bg-orange-500 text-white text-xs font-bold rounded-full">
              {totalUnread > 99 ? '99+' : totalUnread} {language === 'ru' ? 'новых' : 'yangi'}
            </span>
          )}
        </div>
        <p className="text-xs text-gray-400 mb-4">
          {language === 'ru' ? 'Чаты с жителями и группы' : 'Aholi bilan chatlar va guruhlar'}
        </p>

        {/* Filter Tabs */}
        <div className="flex gap-2 mb-3">
          <button
            onClick={() => setActiveFilter('all')}
            className={`px-4 py-2 rounded-[12px] text-xs font-semibold transition-all ${
              activeFilter === 'all'
                ? 'bg-orange-500 text-white shadow-sm'
                : 'bg-gray-100 text-gray-500 hover:text-gray-700'
            }`}
          >
            {language === 'ru' ? 'Все' : 'Hammasi'} ({supportChannels.length})
          </button>
          {unreadCount > 0 && (
            <button
              onClick={() => setActiveFilter('unread')}
              className={`px-4 py-2 rounded-[12px] text-xs font-semibold transition-all flex items-center gap-1.5 ${
                activeFilter === 'unread'
                  ? 'bg-orange-500 text-white shadow-sm'
                  : 'bg-white text-gray-600 border border-gray-200 hover:border-orange-200'
              }`}
            >
              <span className={`w-2 h-2 rounded-full ${activeFilter === 'unread' ? 'bg-white' : 'bg-red-500'}`} />
              {language === 'ru' ? 'Новые' : 'Yangi'} ({unreadCount})
            </button>
          )}
        </div>

        {/* Search + Branch filter */}
        <div className="flex gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder={language === 'ru' ? 'Поиск по имени или сообщению...' : 'Ism yoki xabar bo\'yicha qidirish...'}
              className="w-full pl-9 pr-3 py-2.5 bg-gray-50 border border-gray-200 rounded-[14px] text-sm focus:outline-none focus:ring-2 focus:ring-orange-500/30 focus:border-orange-400 transition-all"
            />
          </div>
          {branchNames.length > 1 && (
            <div className="relative">
              <button
                onClick={() => setShowBranchFilter(!showBranchFilter)}
                className={`flex items-center gap-1 px-3 py-2.5 rounded-[14px] text-xs font-medium border transition-all ${
                  selectedBranch ? 'bg-orange-50 border-orange-200 text-orange-700' : 'bg-gray-50 border-gray-200 text-gray-600 hover:bg-gray-100'
                }`}
              >
                <Building2 className="w-3.5 h-3.5" />
                <ChevronDown className="w-3 h-3" />
              </button>
              {showBranchFilter && (
                <div className="absolute right-0 top-full mt-1 bg-white rounded-[16px] shadow-lg border border-gray-200 py-1.5 z-50 min-w-[160px]">
                  <button
                    onClick={() => { setSelectedBranch(null); setShowBranchFilter(false); }}
                    className={`w-full text-left px-3 py-2 text-xs hover:bg-gray-50 ${!selectedBranch ? 'text-orange-600 font-medium' : 'text-gray-700'}`}
                  >
                    {language === 'ru' ? 'Все филиалы' : 'Barcha filiallar'}
                  </button>
                  {branchNames.map(name => (
                    <button
                      key={name}
                      onClick={() => { setSelectedBranch(name); setShowBranchFilter(false); }}
                      className={`w-full text-left px-3 py-2 text-xs hover:bg-gray-50 ${selectedBranch === name ? 'text-orange-600 font-medium' : 'text-gray-700'}`}
                    >
                      {name}
                    </button>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Section label */}
      <div className="px-5 py-2 border-t bg-gray-50/60">
        <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
          {language === 'ru' ? 'Обращения жителей' : 'Aholi murojatlari'} ({filteredChannels.length})
        </span>
      </div>

      {/* Channel list */}
      <div className="flex-1 overflow-y-auto divide-y divide-gray-100">
        {isLoading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="w-6 h-6 animate-spin text-orange-400" />
          </div>
        ) : filteredChannels.length === 0 ? (
          <div className="px-5 py-12 text-center">
            <div className="w-14 h-14 mx-auto mb-3 bg-gray-100 rounded-[18px] flex items-center justify-center">
              <MessageCircle className="w-7 h-7 text-gray-300" />
            </div>
            <p className="text-sm text-gray-400">
              {activeFilter === 'unread'
                ? (language === 'ru' ? 'Нет новых сообщений' : 'Yangi xabarlar yo\'q')
                : (language === 'ru' ? 'Нет обращений' : 'Murojatlar yo\'q')
              }
            </p>
          </div>
        ) : (
          filteredChannels.map((channel) => {
            const isSelected = selectedChannelId === channel.id;
            const hasUnread = Number(channel.unread_count) > 0;
            const preview = getLastMessagePreview(channel, language);
            const hasMessages = !!channel.last_message_at;

            return (
              <button
                key={channel.id}
                onClick={() => onSelectChannel(channel.id)}
                className={`w-full px-5 py-3.5 flex items-center gap-3 text-left transition-all ${
                  isSelected
                    ? 'bg-orange-50 border-r-2 border-orange-500'
                    : hasUnread
                      ? 'bg-orange-50/40 hover:bg-orange-50/60'
                      : 'hover:bg-gray-50'
                }`}
              >
                {/* Avatar */}
                <div className="relative flex-shrink-0">
                  <div className={`w-11 h-11 rounded-[15px] bg-gradient-to-br ${getAvatarColor(channel.name)} flex items-center justify-center text-white font-semibold text-sm shadow-sm`}>
                    {getInitials(channel.name)}
                  </div>
                  {hasUnread && (
                    <div className="absolute -top-0.5 -right-0.5 min-w-[18px] h-[18px] bg-orange-500 rounded-full flex items-center justify-center shadow-sm">
                      <span className="text-[10px] text-white font-bold px-1">
                        {channel.unread_count! > 99 ? '99+' : channel.unread_count}
                      </span>
                    </div>
                  )}
                </div>

                {/* Info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center justify-between gap-2">
                    <span className={`text-sm truncate ${hasUnread ? 'font-bold text-gray-900' : 'font-medium text-gray-800'}`}>
                      {channel.name}
                    </span>
                    {channel.last_message_at && (
                      <span className={`text-[11px] flex-shrink-0 ${hasUnread ? 'text-orange-500 font-semibold' : 'text-gray-400'}`}>
                        {formatTime(channel.last_message_at, language)}
                      </span>
                    )}
                  </div>
                  {/* Location info */}
                  {(channel.resident_building_name || channel.resident_apartment) && (
                    <div className="text-[11px] text-gray-400 truncate mt-0.5">
                      {channel.resident_branch_name && <span>{channel.resident_branch_name} · </span>}
                      {channel.resident_building_name && <span>{channel.resident_building_name}</span>}
                      {channel.resident_apartment && <span> · {language === 'ru' ? 'кв.' : 'xon.'} {channel.resident_apartment}</span>}
                    </div>
                  )}
                  {/* Last message preview - only show if there are actual messages */}
                  {hasMessages && (
                    <p className={`text-xs truncate mt-0.5 ${hasUnread ? 'text-gray-700 font-medium' : 'text-gray-500'}`}>
                      {preview}
                    </p>
                  )}
                </div>
              </button>
            );
          })
        )}
      </div>
    </div>
  );
}

